const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');
const dotenv = require('dotenv');
const User = require('./models/User');
const Category = require('./models/Category');
const Product = require('./models/Product');

dotenv.config();

const placeholderImage = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNk+A8AAQUBAScY42YAAAAASUVORK5CYII=';
const boyaImage = 'data:image/webp;base64,';
const matkapImage = 'data:image/jpeg;base64,';
const cimentoImage = 'data:image/png;base64,';

const seedDB = async () => {
  try {
    await mongoose.connect(process.env.MONGO_URI || 'mongodb://localhost:27017/altug_yapi');
    console.log('MongoDB bağlantısı başarılı. Temizleniyor...');

    await User.deleteMany();
    await Category.deleteMany();
    await Product.deleteMany();

    console.log('Koleksiyonlar temizlendi.');

    // 1. Admin User
    const salt = await bcrypt.genSalt(10);
    const hashedPassword = await bcrypt.hash('admin123', salt);
    const admin = new User({
      email: 'admin@altugyapi.com',
      password: hashedPassword,
      role: 'admin'
    });
    await admin.save();
    console.log('Yönetici hesabı eklendi: admin@altugyapi.com / admin123');

    // 2. Categories
    const categoriesData = [
      { name: 'Boyalar', description: 'İç ve dış cephe boyaları' },
      { name: 'Hırdavat', description: 'El aletleri ve montaj malzemeleri' },
      { name: 'Yapı Malzemeleri', description: 'Çimento, alçı ve inşaat malzemeleri' }
    ];
    const createdCategories = await Category.insertMany(categoriesData);
    console.log('Kategoriler eklendi.');

    // 3. Products
    const productsData = [
      {
        name: 'Mat Beyaz İç Cephe Boyası',
        description: '20 kg silinebilir mat beyaz iç cephe boyası.',
        price: 850,
        category: createdCategories[0]._id,
        imageUrl: boyaImage
      },
      {
        name: 'Matkap',
        description: 'Darbeli şarjlı matkap seti.',
        price: 1250,
        category: createdCategories[1]._id,
        imageUrl: matkapImage
      },
      {
        name: 'Çimento',
        description: '50 kg portland çimento.',
        price: 150,
        category: createdCategories[2]._id,
        imageUrl: cimentoImage
      }
    ];
    await Product.insertMany(productsData);
    console.log('Ürünler eklendi.');

    console.log('Veritabanı başlatma işlemi tamamlandı.');
    process.exit();
  } catch (error) {
    console.error('Hata:', error);
    process.exit(1);
  }
};

seedDB();
